func intVal(v int) string {
	if v == 0 {
		return ""
	}
	return fmt.Sprintf("%d", v)
}

func poolsJSON(pools []AddressPoolView) string {
	if len(pools) == 0 {
		return "[]"
	}
	result := "["
	for i, p := range pools {
		if i > 0 {
			result += ","
		}
		result += fmt.Sprintf("{base:'%s',size:%d}", p.Base, p.Size)
	}
	return result + "]"
}

